namespace RecipeCommunity.Data;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public static class RecipeStore
{
    private static readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Creamy, spiced tomato sauce with tender chicken pieces.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Cumin", "Tomato sauce", "Heavy cream", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-fry chicken until charred.", "Sauté garlic and ginger, add tomato sauce.", "Stir in cream and spices, simmer 15 minutes.", "Add chicken pieces and cook 5 more minutes.", "Serve over basmati rice."],
            AverageRating = 4.8, RatingCount = 24
        },
        new()
        {
            Id = 3, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy taco shells with fresh toppings.",
            Ingredients = ["Ground beef", "Taco seasoning", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer until thickened.", "Warm taco shells in oven.", "Fill shells with beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa."],
            AverageRating = 4.2, RatingCount = 8
        },
        new()
        {
            Id = 4, Title = "Pad Thai", Category = "Thai",
            Description = "Stir-fried rice noodles with shrimp, peanuts, and tangy sauce.",
            Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime"],
            Steps = ["Soak rice noodles in warm water for 30 minutes.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in the same pan.", "Add noodles, tamarind paste, and fish sauce.", "Toss with shrimp, bean sprouts, and green onions.", "Serve with crushed peanuts and lime wedges."],
            AverageRating = 4.6, RatingCount = 15
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich chocolate cake with a molten center.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F. Grease ramekins.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs, add flour.", "Pour into ramekins and bake 12-14 minutes.", "Invert onto plates and serve immediately."],
            AverageRating = 4.9, RatingCount = 30
        },
        new()
        {
            Id = 6, Title = "Caesar Salad", Category = "Salads",
            Description = "Crisp romaine lettuce with creamy Caesar dressing and croutons.",
            Ingredients = ["Romaine lettuce", "Parmesan cheese", "Croutons", "Caesar dressing", "Lemon juice", "Anchovy paste"],
            Steps = ["Wash and chop romaine lettuce.", "Prepare dressing with anchovy paste, lemon, and parmesan.", "Toss lettuce with dressing.", "Top with croutons and shaved parmesan.", "Serve immediately."],
            AverageRating = 4.0, RatingCount = 6
        },
    ];

    public static IReadOnlyList<Recipe> All => _recipes;

    public static IEnumerable<string> Categories =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c);

    public static IEnumerable<Recipe> ByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase));

    public static Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public static void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public static void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null) return;
        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

@page "/recipes/category/{CategoryName}"
@using RecipeCommunity.Data

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/recipes">All Categories</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (!recipes.Any())
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                                <small class="text-muted ms-1">(@recipe.AverageRating)</small>
                            </span>
                            <a href="/recipes/@recipe.Id" class="btn btn-sm btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IEnumerable<Recipe> recipes => RecipeStore.ByCategory(CategoryName);
}

@page "/recipes/{Id:int}"
@using RecipeCommunity.Data

<PageTitle>@(recipe?.Title ?? "Recipe Not Found")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="/recipes/category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <div class="mb-4">
        <RecipeCommunity.Client.Components.StarRating RecipeId="recipe.Id"
                                                      CurrentRating="recipe.AverageRating"
                                                      RatingCount="recipe.RatingCount"
                                                      @rendermode="InteractiveWebAssembly" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-4">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
