@namespace RecipeCommunity.Client.Components

<div class="d-inline-flex align-items-center">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= hoverRating ? "star-hover" : star <= displayRating ? "star-filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => hoverRating = star"
              @onmouseout="() => hoverRating = 0"
              style="cursor:pointer; font-size:1.5rem; color: @(star <= (hoverRating > 0 ? hoverRating : displayRating) ? "#ffc107" : "#dee2e6");">
            ★
        </span>
    }
    <span class="ms-2 text-muted small">
        @if (submitted)
        {
            <span class="text-success">Thanks! You rated @userRating star(s).</span>
        }
